sql:
SELECT system_id, AVG(annual_consumption_kwh) AS average_annual_consumption_kwh
FROM lighting_systems
GROUP BY system_id;

SELECT annual_consumption_kwh
FROM lighting_systems
WHERE system_id = 1;

SELECT SUM(savings_kwh) AS total_savings_kwh
FROM energy_savings
WHERE date = '2023-05-02';

SELECT AVG(ec.consumption_kwh * 365) AS average_annual_consumption
FROM lighting_systems ls
JOIN energy_consumption ec ON ls.system_id = ec.system_id;

SELECT system_name, total_power
FROM lighting_systems
ORDER BY total_power DESC;

external_knowledge:
- 'gleams bright' metaphorically refers to an 'active' system status;
- 'operates for 40 hours a week' is the literal translation of the scheduled hours criterion;
- 'from the first day of April to the last' indicates the date range from April 1, 2023, to April 30, 2023.
